Below is a **complete, self‑contained example** that shows how to expose a C++ iterator (from the fictitious `libpcapng` library) to OCaml.  
It consists of

* `pcapng.mli` – the public OCaml interface,
* `pcapng_stubs.cpp` – the C++/C stub file that talks to `libpcapng` and to the OCaml runtime,
* a short **build recipe** (make‑style) that produces a static library `libpcapng_stubs.a` and an OCaml module `Pcapng`.

You can copy the three fragments into a single directory, adjust the include‑paths for the real `libpcapng` headers, and compile with the commands that follow.  
The code is deliberately simple, yet it shows all the important techniques:

* wrapping a C++ object inside an OCaml custom block,
* providing a finaliser,
* converting a C++ `frame` structure into an OCaml record,
* calling back an OCaml closure for each element,
* propagating OCaml exceptions out of the C++ loop.

---

## 1.  The OCaml interface – `pcapng.mli`

```ocaml
(** pcapng.mli – public OCaml API for the libpcapng bindings *)

(** Opaque handle to an opened pcapng file. *)
type t

(** A single captured frame.  Only a tiny subset of the real fields is
    exposed – you can extend the record as needed. *)
type frame = {
  timestamp : int64;   (** nanoseconds since epoch *)
  data      : bytes;   (** raw packet bytes *)
}

(** Open a pcapng file.  Raises [Sys_error] if the file cannot be opened. *)
val open_file : string -> t

(** Explicitly close a file.  The underlying C++ object is also freed
    automatically by the OCaml garbage collector, so this function is
    optional but convenient for deterministic resource release. *)
val close : t -> unit

(** Iterate over all frames in the file, applying the supplied OCaml
    callback to each frame.  The callback runs **inside** the C++ iterator
    loop, so it may raise an exception; the exception is propagated to the
    caller of [iter] and the iteration stops immediately. *)
val iter : t -> (frame -> unit) -> unit
```

---

## 2.  The C/C++ stub – `pcapng_stubs.cpp`

> **Important** – This file must be compiled with a C++ compiler (`g++`,
> `clang++`, …) because it links against the C++ library `libpcapng`.  
> The functions that OCaml will call are exported with `extern "C"` so that
> the OCaml runtime can find them.

```cpp
/* pcapng_stubs.cpp – C++ stub file for the OCaml bindings.
 *
 *   - The real libpcapng header is assumed to provide:
 *
 *         class PcapngFile {
 *         public:
 *           explicit PcapngFile(const std::string& filename);
 *           ~PcapngFile();
 *
 *           struct Frame {
 *               uint64_t timestamp_ns;   // nanoseconds since epoch
 *               const uint8_t* data;     // pointer to packet bytes
 *               size_t        length;    // length of data
 *           };
 *
 *           class iterator {
 *           public:
 *               iterator(const iterator&) = default;
 *               iterator& operator++();   // advance
 *               bool operator==(const iterator&) const;
 *               bool operator!=(const iterator&) const;
 *               const Frame& operator*() const;
 *           };
 *
 *           iterator begin() const;
 *           iterator end()   const;
 *         };
 *
 *   - The real library may have a different API – adapt the code below
 *     accordingly.
 */

#define CAML_NAME_SPACE          /* avoid clashes with other libs */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <string>
#include <exception>
#include <stdexcept>
#include <cstring>   // memcpy

/* --------------------------------------------------------------- */
/* 1.  Include the real libpcapng header (adjust the path).        */
#include "libpcapng.hpp"   // <-- replace with the actual header

/* --------------------------------------------------------------- */
/* 2.  The OCaml custom block that holds the C++ object.           */

struct pcapng_wrapper {
    PcapngFile* file;   // owned pointer, deleted in the finaliser
};

/* Finaliser – called when the OCaml value is GC‑collected. */
static void pcapng_finalize(value v) {
    pcapng_wrapper* w = (pcapng_wrapper*)Data_custom_val(v);
    delete w->file;
    w->file = nullptr;
}

/* Custom operations table.  No comparison or serialization needed. */
static struct custom_operations pcapng_custom_ops = {
    "pcapng_binding_v1",          /* identifier */
    pcapng_finalize,             /* finaliser */
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
};

/* Helper to retrieve the wrapper from an OCaml value. */
static inline pcapng_wrapper* Pcapng_val(value v) {
    return (pcapng_wrapper*)Data_custom_val(v);
}

/* --------------------------------------------------------------- */
/* 3.  OCaml‑visible primitives.                                   */

/* 3.1. open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    /* Convert OCaml string to std::string */
    std::string path = std::string(String_val(v_path));

    /* Allocate the custom block */
    v_res = caml_alloc_custom(&pcapng_custom_ops,
                              sizeof(pcapng_wrapper),
                              0,   /* memory cost (bytes) – 0 is fine */
                              1);  /* finaliser runs when block is freed */

    pcapng_wrapper* w = Pcapng_val(v_res);
    try {
        w->file = new PcapngFile(path);
    } catch (const std::exception& e) {
        caml_raise_with_string(*caml_named_value("Pcapng_error"),
                               e.what());
    }

    CAMLreturn(v_res);
}

/* 3.2. close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    pcapng_wrapper* w = Pcapng_val(v_handle);
    if (w->file) {
        delete w->file;
        w->file = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* 3.3. iter : t -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter(value v_handle, value v_cb) {
    CAMLparam2(v_handle, v_cb);
    CAMLlocal3(v_frame, v_timestamp, v_data);

    pcapng_wrapper* w = Pcapng_val(v_handle);
    if (!w->file) caml_failwith("Pcapng.iter: file already closed");

    /* The callback must be a closure; we keep a rooted copy so that the
       GC does not move it while we are in the C++ loop. */
    value *cb_closure = caml_named_value("pcapng_iter_callback");
    /* (the above line is only to keep the compiler happy – we will use
       v_cb directly) */

    try {
        for (auto it = w->file->begin(); it != w->file->end(); ++it) {
            const PcapngFile::Frame& f = *it;

            /* ---- Build the OCaml frame record ---- */
            /* timestamp : int64 */
            v_timestamp = caml_copy_int64((int64_t)f.timestamp_ns);

            /* data : bytes */
            v_data = caml_alloc_string(f.length);
            if (f.length > 0) {
                memcpy(String_val(v_data), f.data, f.length);
            }

            /* Allocate the record (timestamp, data) */
            v_frame = caml_alloc(2, 0);               // 2 fields, tag 0
            Store_field(v_frame, 0, v_timestamp);
            Store_field(v_frame, 1, v_data);

            /* ---- Call the OCaml callback ---- */
            value res = caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(res)) {
                /* Propagate the exception out of the iterator. */
                caml_raise(res);
            }
        }
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }

    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------- */
/* 4.  Register a custom exception (optional but nice).            */

extern "C" CAMLprim value caml_pcapng_register_exn(value v_exn) {
    CAMLparam1(v_exn);
    caml_register_named_value("Pcapng_error", v_exn);
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------- */
/* 5.  OCaml stub declarations (to be compiled with ocamlc)       */
/*    The .ml file that the user will `open Pcapng` can simply be   */
/*    a thin wrapper around the primitives above.                  */

```

